#include <stdio.h>
#include <inttypes.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t x, y;
        scanf("%" PRId64 " %" PRId64, &x, &y);
        if ( ((x + y) & 1LL) == 0 )
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}

